```spl
// fields — inclure des champs (garder)
| fields host, src_ip, dest_ip, action

// fields - — exclure des champs (supprimer)
| fields - _raw, _indextime, linecount

// rename — renommer
| rename src_ip AS source, dest_ip AS destination

// table — comme fields mais formate en tableau
| table _time, host, src_ip, action, bytes
// Différence : table réordonne les colonnes selon l'ordre spécifié

// eval — créer des champs calculés (équivalent extend KQL)
| eval severity=if(status>=500, "critical", if(status>=400, "warning", "ok"))
| eval duration_min=round(duration/60, 2)
| eval full_host=host+"."+domain
| eval is_admin=if(match(username, "admin"), 1, 0)
```

```spl
// match() — regex dans where
| where match(src_ip, "^192\\.168\\.")
| where match(filename, "\\.(exe|dll|bat)$")

// like() — pattern SQL
| where like(username, "%admin%")  // contient admin
| where like(filename, "%.exe")     // se termine par .exe
| where like(host, "DC%")           // commence par DC

// cidrmatch() — adresse dans un sous-réseau
| where cidrmatch("10.0.0.0/8", src_ip)
| where NOT cidrmatch("192.168.0.0/16", src_ip)

// Wildcards dans la recherche de base (pas dans where)
index=main sourcetype=access* host=web*

// Chercher une phrase exacte (guillemets)
index=main "access denied"

// Opérateur NOT (exclure)
index=main NOT host=monitor-* NOT sourcetype=heartbeat
```
